scwin.gr_SeaAFR_oncellclick = async function (rowIndex, columnIndex, columnId) {
  if (rowIndex >= 0 && scwin.clickRow != rowIndex) {
    ds_SeaAFR.undoAll();
    await scwin.f_RetrieveCont(rowIndex);
    if (ds_SeaAFR.getCellData(rowIndex, "flag") == "2") {
      gr_SeaAFR.setReadOnly("grid", false);
      scwin.f_Set("RETRIEVE2");
    } else if (ds_SeaAFR.getCellData(rowIndex, "flag") == "1") {
      if (columnId == "chk") {
        await $c.win.alert($p, '등록되지 않은 AFR 정보입니다.');
      }
      if (ds_SeaAFRMarks.getRowCount() > 0) {
        let markVal = ds_SeaAFRMarks.getCellData(ds_SeaAFRMarks.getRowPosition(), "mark");
        let Split = markVal.split("\n");
        if (Split[0] != undefined) txt_mark1.setValue(Split[0]);
        if (Split[1] != undefined) txt_mark2.setValue(Split[1]);
        if (Split[2] != undefined) txt_mark3.setValue(Split[2]);
        if (Split[3] != undefined) txt_mark4.setValue(Split[3]);
      }
      gr_SeaAFR.setReadOnly("grid", true);
      scwin.f_Set("RETRIEVE");
    }
    scwin.clickRow = rowIndex;
  }
};
